import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "Habitat Residency — 3-Month Program for Solo Founders",
  description: "An intensive in-person residency for solo founders to build, launch, and scale their startups — together.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body className="antialiased">
        {children}
      </body>
    </html>
  );
}

